import json
import re

# Load data
users_2016 = locals()['var_functions.query_db:122']
reviews_all = locals()['var_functions.query_db:6']
businesses_all = locals()['var_functions.query_db:136']

# Get 2016 user IDs
user_ids_2016 = set([u['user_id'] for u in users_2016])

# Count reviews per business (by business_ref)
reviews_per_business = {}
for review in reviews_all:
    if review['user_id'] in user_ids_2016:
        biz_ref = review['business_ref']
        reviews_per_business[biz_ref] = reviews_per_business.get(biz_ref, 0) + 1

# Map business IDs to refs
biz_id_to_ref = {}
for biz in businesses_all:
    biz_id = biz['business_id']
    biz_ref = biz_id.replace('businessid_', 'businessref_')
    biz_id_to_ref[biz_id] = biz_ref

# Extract categories from business descriptions
def get_categories_from_desc(description):
    if not description:
        return []

    desc = str(description)
    desc_lower = desc.lower()

    # Look for the categories list
    categories_text = ""

    if 'services in' in desc_lower:
        parts = desc.split('services in')
        if len(parts) > 1:
            categories_text = parts[1]
    elif 'including' in desc_lower:
        parts = desc.split('including')
        if len(parts) > 1:
            categories_text = parts[1]
    elif 'services' in desc_lower:
        # Last resort: try to find a list of comma-separated items
        # Look for commas in the latter part of the description
        words = desc.split()
        for i, word in enumerate(words):
            if ',' in word and i > 5:  # Comma after some text
                # Extract from here onwards
                categories_text = ' '.join(words[i:])
                break

    # Clean up
    if not categories_text:
        return []

    # Remove trailing period and what follows
    if '.' in categories_text:
        categories_text = categories_text.split('.')[0]

    # Split by comma
    raw_items = categories_text.split(',')

    categories = []
    for item in raw_items:
        item = item.strip()
        if not item:
            continue

        # Remove "and" prefix
        if item.lower().startswith('and '):
            item = item[4:]

        # Clean up
        if len(item) > 3:
            # Remove special chars from start/end
            item = re.sub(r'^[^a-zA-Z]+', '', item)
            item = re.sub(r'[^a-zA-Z]+$', '', item)
            if item:
                categories.append(item)

    return categories

# Get categories for each business
business_categories = {}
for biz in businesses_all:
    biz_id = biz['business_id']
    biz_ref = biz_id.replace('businessid_', 'businessref_')
    desc = biz.get('description', '')
    cats = get_categories_from_desc(desc)
    business_categories[biz_ref] = cats

# Count reviews per category
category_review_counts = {}
for biz_ref, review_count in reviews_per_business.items():
    categories = business_categories.get(biz_ref, [])
    for category in categories:
        category_review_counts[category] = category_review_counts.get(category, 0) + review_count

# Clean up and present top 5 categories
top_categories = []
for category, count in sorted(category_review_counts.items(), key=lambda x: x[1], reverse=True):
    if count > 0 and category:
        # Fix common extraction artifacts
        clean_cat = category
        if clean_cat.startswith('Cluding'):
            clean_cat = clean_cat[7:].strip()
        elif clean_cat.startswith('And'):
            clean_cat = clean_cat[3:].strip()

        # Title case for display
        clean_cat = clean_cat.title()

        # Avoid duplicates
        if not any(existing[0].lower() == clean_cat.lower() for existing in top_categories):
            top_categories.append((clean_cat, count))
            if len(top_categories) == 5:
                break

# Format final answer
if top_categories:
    answer = "The top 5 business categories reviewed by users who registered in 2016 are:\n"
    for i, (category, count) in enumerate(top_categories, 1):
        answer += f"\n{i}. {category}: {count} reviews"
    answer += f"\n\nUsers registered in 2016: {len(user_ids_2016)}"
    answer += f"\nTotal reviews by these users: {sum(reviews_per_business.values())}"
else:
    answer = "Could not extract business categories from the available data."

print('__RESULT__:')
print(json.dumps({'answer': answer}))

